def normalize_text(text: str, options: NormalizerOptions | None = None) -> str:
    opts = options or NormalizerOptions()
    s = text
    if opts.nfkc:
        s = unicodedata.normalize("NFKC", s)
    if opts.katakana_to_hiragana:
        s = _katakana_to_hiragana(s)
    if opts.lowercase:
        s = s.lower()
    return s

def _katakana_to_hiragana(text: str) -> str:
    out: list[str] = []
    for ch in text:
        cp = ord(ch)
        if _KATAKANA_START <= cp <= _KATAKANA_END:
            out.append(chr(cp - _KATAKANA_START + _HIRAGANA_START))
        else:
            out.append(ch)
    return "".join(out)

def _is_strong_slug(slug: str) -> bool:
    """A slug is "strong" iff it contains at least one ASCII [a-z] letter.

    Empty slugs and numeric/symbol-only slugs ("1", "3-1", "2-") are weak
    and must be replaced with a hash to avoid collisions across JP titles
    that ASCII-fold to the same residue.
    """
    if not slug:
        return False
    return bool(_ASCII_ALPHA_RE.search(slug))

